package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testTrim_StringInstance() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        String input = "  test string  ";

        // When
        Object result = csvFormat.trim(input);

        // Then
        assertEquals("test string", result);
    }

    @Test
    public void testTrim_CharSequenceInstance() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CharSequence input = "  test char sequence  ";

        // When
        Object result = csvFormat.trim(input);

        // Then
        assertEquals("test char sequence", result);
    }

    @Test
    public void testTrim_PositiveCase() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CharSequence input = "  test  ";

        // When
        Object result = csvFormat.trim(input);

        // Then
        assertEquals("test", result);
    }

    @Test
    public void testTrim_NoTrimNeeded() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CharSequence input = "test";

        // When
        Object result = csvFormat.trim(input);

        // Then
        assertEquals("test", result);
    }
}
